"use client";

// Next.js app-router page for the Complete hire and onboard workflow.
// Generated by flowforge JTBD generator.
import * as React from "react";
import { CompleteHireStep } from "@/components/complete-hire/CompleteHireStep";
import { fireWorkflowEvent } from "../../hiring_pipeline/runtimeClient";

export const dynamic = "force-dynamic";

const INITIAL_STATE = "intake";
const RUNTIME_MODE = process.env.NEXT_PUBLIC_FLOWFORGE_DEMO_MODE === "1" ? "demo" : "api";
const TENANT_ID = process.env.NEXT_PUBLIC_FLOWFORGE_TENANT_ID ?? "default";

function createInstanceId(): string {
	if (typeof window !== "undefined") {
		const fromQuery = new URLSearchParams(window.location.search).get("instance_id");
		if (fromQuery) return fromQuery;
	}
	if (typeof crypto !== "undefined" && "randomUUID" in crypto) {
		return crypto.randomUUID();
	}
	return `local-${Date.now().toString(36)}`;
}

function demoNextState(current: string, event: string): string {
	if (event === "submit") return "review";
	if (event === "approve") return "done";
	return current;
}

export default function CompleteHirePage(): React.ReactElement {
	const [instanceId] = React.useState(createInstanceId);
	const [state, setState] = React.useState(INITIAL_STATE);
	const [error, setError] = React.useState<string | null>(null);

	const onEvent = React.useCallback(
		async (event: string, payload?: Record<string, unknown>): Promise<void> => {
			setError(null);
			if (RUNTIME_MODE === "demo") {
				setState((current) => demoNextState(current, event));
				return;
			}
			try {
				const result = await fireWorkflowEvent({
					workflowPath: "complete-hire",
					event,
					payload,
					instanceId,
					tenantId: TENANT_ID,
				});
				setState(result.state);
			} catch (err) {
				setError(err instanceof Error ? err.message : "Workflow event failed");
			}
		},
		[instanceId],
	);

	return (
		<main data-flowforge-runtime-mode={RUNTIME_MODE}>
			<h1>Complete hire and onboard</h1>
			{error ? <p role="alert">{error}</p> : null}
			<CompleteHireStep instanceId={instanceId} state={state} onEvent={onEvent} />
		</main>
	);
}
